def compute_score() -> tuple[str, float]:
    """
    Code-based verification that footer contains the exact required text.
    Proves text accuracy through direct XML parsing and text extraction.
    """
    try:
        from pptx import Presentation
        import zipfile

        required_text = "Fundamental Accounting Concepts"
        pres = Presentation(modified_ppt_path)
        total_slides = len(pres.slides)
        slides_with_correct_text = 0

        # Method 1: Check through python-pptx API
        for slide in pres.slides:
            has_correct_text = False
            exact_text_found = False

            # Check all text shapes on the slide
            for shape in slide.shapes:
                if hasattr(shape, 'text'):
                    # Check for exact text match (case sensitive)
                    if required_text in shape.text:
                        has_correct_text = True
                        if shape.text == required_text:
                            exact_text_found = True
                            break

            if has_correct_text and exact_text_found:
                slides_with_correct_text += 1

        # Method 2: Verify through raw XML parsing for more thorough check
        try:
            with zipfile.ZipFile(modified_ppt_path, 'r') as pptx_zip:
                xml_slides_with_correct_text = 0

                # Check each slide's XML for exact text
                for i in range(1, total_slides + 1):
                    slide_xml_path = f'ppt/slides/slide{i}.xml'
                    try:
                        with pptx_zip.open(slide_xml_path) as slide_file:
                            slide_content = slide_file.read().decode('utf-8')

                            # Check for exact text in XML
                            if required_text in slide_content:
                                xml_slides_with_correct_text += 1
                    except KeyError:
                        continue

                # Use the min for rigorous verification
                slides_with_correct_text = min(slides_with_correct_text, xml_slides_with_correct_text)

        except Exception:
            # Fall back to python-pptx method
            pass

        # Score based on text accuracy
        if slides_with_correct_text == total_slides:
            return f"Footer text '{required_text}' verified correct on all {total_slides} slides.", 1.0
        elif slides_with_correct_text > 0:
            score = slides_with_correct_text / total_slides
            return f"Correct footer text found on {slides_with_correct_text}/{total_slides} slides.", score
        else:
            return f"Required footer text '{required_text}' not found on any slide through XML verification.", 0.0

    except Exception as e:
        return f"Error during footer text verification: {str(e)[:100]}", 0.0
